import json, sys
from pathlib import Path

path = Path('.yoyo/state/events.jsonl')
if not path.is_file():
    print('No events file')
    sys.exit(0)

events = []
with open(path, encoding='utf-8', errors='replace') as f:
    for i, line in enumerate(f, 1):
        line = line.strip()
        if not line:
            continue
        try:
            events.append(json.loads(line))
        except json.JSONDecodeError:
            continue

def event_type(e):
    v = e.get('event_type') or e.get('kind')
    if isinstance(v, str):
        return v
    p = e.get('payload')
    if isinstance(p, dict):
        m = p.get('_yoyo')
        if isinstance(m, dict) and isinstance(m.get('event_type'), str):
            return m['event_type']
    return ''

def payload(e):
    v = e.get('payload')
    if not isinstance(v, dict):
        return {}
    w = v.get('value')
    if set(v.keys()).issubset({'_yoyo', 'value'}) and isinstance(w, dict):
        return w
    return v

def run_id(e, data):
    for val in (
        e.get('run_id'),
        (e.get('payload') or {}).get('_yoyo', {}).get('run_id') if isinstance(e.get('payload'), dict) and isinstance((e.get('payload') or {}).get('_yoyo'), dict) else None,
        data.get('run_id'),
        (data.get('_yoyo') if isinstance(data.get('_yoyo'), dict) else {}).get('run_id'),
    ):
        if isinstance(val, str) and val:
            return val
    return None

run_started = set()
run_completed = set()
session_started = set()
session_completed = set()
failure_observed = set()

for e in events:
    kind = event_type(e)
    data = payload(e)
    rid = run_id(e, data)
    if not rid:
        continue
    is_session = data.get('phase') == 'session'
    if kind == 'RunStarted':
        if is_session:
            session_started.add(rid)
        else:
            run_started.add(rid)
    elif kind == 'SessionStarted':
        session_started.add(rid)
    elif kind == 'RunCompleted':
        if is_session:
            session_completed.add(rid)
        else:
            run_completed.add(rid)
    elif kind == 'FailureObserved':
        failure_observed.add(rid)

# Non-session runs
incomplete = run_started - run_completed
unmatched_completed = run_completed - run_started
completed_without_failure = {r for r in run_completed if r not in failure_observed}

print(f'Total events: {len(events)}')
print(f'RunStarted (non-session): {len(run_started)}')
print(f'RunCompleted (non-session): {len(run_completed)}')
print(f'Incomplete (started, no completed): {len(incomplete)}')
print(f'Unmatched completed (completed, no start): {len(unmatched_completed)}')
print(f'Session runs started: {len(session_started)}')
print(f'Session runs completed: {len(session_completed)}')
print(f'FailureObserved: {len(failure_observed)}')
print(f'Completed without FailureObserved: {len(completed_without_failure)}')

# Show incomplete runs
if incomplete:
    print(f'\\nIncomplete runs:')
    for rid in sorted(incomplete)[:10]:
        print(f'  {rid}')
    if len(incomplete) > 10:
        print(f'  ... and {len(incomplete) - 10} more')

# Show completed without failure
if completed_without_failure:
    print(f'\\nCompleted without FailureObserved:')
    for rid in sorted(completed_without_failure)[:10]:
        print(f'  {rid}')
"

