import json
events = []
with open('.yoyo/state/events.jsonl') as f:
    for line in f:
        line = line.strip()
        if line:
            try:
                events.append(json.loads(line))
            except:
                pass
# Find runs with RunStarted but no RunCompleted
run_ids_seen = set()
run_started = {}
for e in events:
    rid = e.get('run_id','')
    if not rid: continue
    if e.get('event_type') == 'RunStarted':
        run_started[rid] = e
        run_ids_seen.add(rid)
    elif e.get('event_type') == 'RunCompleted':
        run_ids_seen.add(rid)

# Now find runs with RunStarted but no RunCompleted
from collections import defaultdict
statuses = defaultdict(list)
for e in events:
    rid = e.get('run_id','')
    if not rid: continue
    statuses[rid].append(e.get('event_type'))

open_runs = []
for rid, types in statuses.items():
    if 'RunStarted' in types and 'RunCompleted' not in types:
        open_runs.append(rid)

print(f'Total open runs: {len(open_runs)}')
for r in sorted(open_runs)[:15]:
    print(f'  {r}: events={len(statuses[r])} types={set(statuses[r])}')
print('---')
# also check for runs that have FailureObserved but no RunStarted
"""
